phone_stand.scad_template:
// Parametric Phone Stand
phone_width = ${phone_width};
angle = ${angle};
base_depth = ${base_depth};
thickness = ${thickness};
lip_height = ${lip_height};

module phone_stand() {
    // Base plate
    cube([phone_width + 10, base_depth, thickness]);
    // Back support
    translate([0, base_depth - thickness, 0])
        rotate([90 - angle, 0, 0])
            cube([phone_width + 10, base_depth * 0.8, thickness]);
    // Front lip
    translate([0, thickness, 0])
        cube([phone_width + 10, thickness, lip_height]);
    // Side rails
    for (x = [0, phone_width + 10 - thickness]) {
        translate([x, 0, 0])
            cube([thickness, base_depth * 0.4, lip_height]);
    }
}

phone_stand();

hook.scad_template:
// Parametric Wall Hook
hook_radius = ${hook_radius};
thickness = ${thickness};
width = ${width};
plate_height = ${plate_height};
screw_hole_dia = ${screw_hole_dia};

module wall_hook() {
    difference() {
        union() {
            // Mounting plate
            cube([width, thickness, plate_height]);
            // Hook arm
            translate([0, 0, 0])
                cube([width, hook_radius + thickness * 2, thickness]);
            // Hook curve
            translate([0, hook_radius + thickness, thickness])
                rotate([0, 90, 0])
                    difference() {
                        cylinder(h=width, r=hook_radius + thickness, $fn=60);
                        cylinder(h=width, r=hook_radius, $fn=60);
                        translate([-hook_radius * 2, 0, 0])
                            cube([hook_radius * 4, hook_radius * 2, width]);
                    }
        }
        // Screw hole
        translate([width/2, -1, plate_height * 0.7])
            rotate([-90, 0, 0])
                cylinder(h=thickness+2, d=screw_hole_dia, $fn=30);
    }
}

wall_hook();

box_with_lid.scad_template:
// Parametric Box with Snap Lid
iw = ${inner_width};
id = ${inner_depth};
ih = ${inner_height};
wall = ${wall};
cr = ${corner_radius};

module rounded_box(w, d, h, r) {
    if (r > 0) {
        hull() {
            for (x = [r, w-r]) for (y = [r, d-r])
                translate([x, y, 0]) cylinder(h=h, r=r, $fn=30);
        }
    } else {
        cube([w, d, h]);
    }
}

module box() {
    ow = iw + wall*2;
    od = id + wall*2;
    oh = ih + wall;
    difference() {
        rounded_box(ow, od, oh, cr);
        translate([wall, wall, wall])
            rounded_box(iw, id, ih+1, max(0, cr-wall));
    }
    // Lip for lid
    translate([wall-0.4, wall-0.4, oh])
        difference() {
            rounded_box(iw+0.8, id+0.8, 2, max(0, cr-wall));
            translate([1, 1, -0.1])
                rounded_box(iw-1.2, id-1.2, 2.2, max(0, cr-wall-1));
        }
}

module lid() {
    ow = iw + wall*2;
    od = id + wall*2;
    translate([ow + 10, 0, 0]) {
        rounded_box(ow, od, wall, cr);
        translate([wall+0.2, wall+0.2, wall])
            difference() {
                rounded_box(iw-0.4, id-0.4, 2.5, max(0, cr-wall));
                translate([1.2, 1.2, -0.1])
                    rounded_box(iw-2.8, id-2.8, 2.7, max(0, cr-wall-1));
            }
    }
}

box();
lid();

cable_clip.scad_template:
// Parametric Cable Clip
cable_dia = ${cable_dia};
channels = ${channels};
base_w = ${base_width};

wall = 2;
total_w = base_w * channels;

module clip() {
    difference() {
        union() {
            // Base pad
            cube([total_w, base_w, 2]);
            // Clip arms
            for (ch = [0:channels-1]) {
                cx = base_w/2 + ch * base_w;
                translate([cx, base_w/2, 2])
                    difference() {
                        cylinder(h=cable_dia/2 + wall, d=cable_dia + wall*2, $fn=40);
                        cylinder(h=cable_dia/2 + wall + 1, d=cable_dia, $fn=40);
                        // Entry slot
                        translate([0, 0, cable_dia*0.3])
                            cube([cable_dia*0.7, cable_dia*2, cable_dia], center=true);
                    }
            }
        }
        // Flatten bottom
        translate([-1, -1, -1]) cube([total_w+2, base_w+2, 1]);
    }
}

clip();

shelf_bracket.scad_template:
// Parametric Shelf Bracket
arm = ${arm_length};
wall_arm = ${wall_length};
w = ${width};
t = ${thickness};
hole_d = ${hole_dia};

module bracket() {
    difference() {
        union() {
            // Wall plate
            cube([w, t, wall_arm]);
            // Shelf arm
            cube([w, arm, t]);
            // Gusset (triangle)
            translate([0, 0, 0])
                linear_extrude(height=w)
                    polygon([[0,t],[0,wall_arm],[t,t]]);
            // Mirrored gusset for width
        }
        // Mounting holes
        for (z = [wall_arm*0.25, wall_arm*0.75]) {
            translate([w/2, -1, z])
                rotate([-90, 0, 0])
                    cylinder(h=t+2, d=hole_d, $fn=30);
        }
    }
}

bracket();

nameplate.scad_template:
// Parametric Nameplate
txt = "${text_string}";
fs = ${font_size};
pw = ${plate_width};
ph = ${plate_height};
bd = ${base_depth};
t = 3;

module nameplate() {
    // Base wedge
    hull() {
        cube([pw, bd, t]);
        translate([0, 0, ph])
            cube([pw, t, t]);
    }
    // Raised text
    translate([pw/2, bd*0.3, ph*0.4])
        rotate([atan2(ph, bd-t), 0, 0])
            linear_extrude(height=1.2)
                text(txt, size=fs, halign="center", valign="center", font="Liberation Sans:style=Bold");
}

nameplate();

pencil_holder.scad_template:
// Parametric Pencil Holder
d = ${diameter};
h = ${height};
wall = ${wall};
hex = ${hex_size};

module pencil_holder() {
    difference() {
        cylinder(h=h, d=d, $fn=80);
        translate([0, 0, 3])
            cylinder(h=h, d=d - wall*2, $fn=80);
        // Honeycomb cutouts
        for (a = [0:30:359]) {
            for (z = [15:hex*2.2:h-15]) {
                rotate([0, 0, a])
                    translate([d/2 - wall/2, 0, z])
                        rotate([0, 90, 0])
                            cylinder(h=wall+2, d=hex, $fn=6, center=true);
            }
        }
    }
}

pencil_holder();

headphone_stand.scad_template:
// Parametric Headphone Stand
h = ${height};
bw = ${base_width};
aw = ${arm_width};
t = ${thickness};
hd = ${hook_depth};

module stand() {
    // Base plate
    hull() {
        cylinder(h=t, d=bw, $fn=60);
    }
    // Upright
    translate([-aw/2, -t/2, 0])
        cube([aw, t, h - hd/2]);
    // Top hook
    translate([0, 0, h - hd/2])
        rotate([0, 0, 0]) {
            // Curved top rest
            translate([-aw/2, -t/2, 0])
                cube([aw, t, hd/4]);
            translate([0, hd/2, hd/4])
                rotate([0, 90, 0])
                    difference() {
                        cylinder(h=aw, r=hd/2, $fn=60, center=true);
                        cylinder(h=aw+2, r=hd/2-t, $fn=60, center=true);
                        translate([0, -hd, 0])
                            cube([hd*2, hd*2, aw+4], center=true);
                    }
        }
}

stand();

drawer_organizer.scad_template:
// Parametric Drawer Organizer
w = ${width};
d = ${depth};
h = ${height};
cols = ${cols};
rows = ${rows};
wall = ${wall};

module organizer() {
    cell_w = (w - wall * (cols + 1)) / cols;
    cell_d = (d - wall * (rows + 1)) / rows;
    difference() {
        cube([w, d, h]);
        for (c = [0:cols-1]) {
            for (r = [0:rows-1]) {
                translate([wall + c * (cell_w + wall), wall + r * (cell_d + wall), wall])
                    cube([cell_w, cell_d, h]);
            }
        }
    }
}

organizer();

sd_card_holder.scad_template:
// Parametric SD Card Holder
sd_n = ${sd_slots};
micro_n = ${micro_slots};
wall = ${wall};

sd_w = 24.5; sd_h = 32.5; sd_t = 2.5;
micro_w = 11.5; micro_h = 15.5; micro_t = 1.5;
slot_gap = 1;

total_w = max(sd_n * (sd_t + slot_gap + wall), micro_n * (micro_t + slot_gap + wall)) + wall;
total_d = max(sd_w, micro_w) + wall * 2;
total_h = sd_h + micro_h + wall * 3;

module holder() {
    difference() {
        cube([total_w, total_d, total_h]);
        // SD slots
        for (i = [0:sd_n-1]) {
            translate([wall + i * (sd_t + slot_gap + wall), wall, wall])
                cube([sd_t + slot_gap, sd_w + 1, sd_h]);
        }
        // MicroSD slots
        for (i = [0:micro_n-1]) {
            translate([wall + i * (micro_t + slot_gap + wall), wall, sd_h + wall * 2])
                cube([micro_t + slot_gap, micro_w + 1, micro_h]);
        }
    }
}

holder();

laptop_stand_riser.scad_template:
// Parametric Laptop Stand Riser
w = ${width};
d = ${depth};
fh = ${front_height};
bh = ${back_height};
t = ${thickness};

module riser() {
    // Side profile (wedge shape)
    linear_extrude(height=w)
        polygon([[0,0], [d,0], [d,bh], [d-t,bh], [d-t,t], [t,t], [t,fh], [0,fh]]);
    // Anti-slip ridges on top
    for (y = [t*2:10:d-t*2]) {
        translate([y, fh + (bh-fh)*(y/d) - 1, 0])
            cube([2, 1, w]);
    }
}

riser();

coat_hook_multi.scad_template:
// Parametric Multi-Peg Coat Hook
pegs = ${pegs};
peg_l = ${peg_length};
peg_d = ${peg_dia};
sp = ${spacing};
ph = ${plate_height};
hd = ${hole_dia};
t = 5;

total_w = (pegs - 1) * sp + peg_d + 20;

module coat_hook() {
    difference() {
        union() {
            // Back plate
            translate([-10, 0, 0])
                cube([total_w, t, ph]);
            // Pegs
            for (i = [0:pegs-1]) {
                translate([i * sp + peg_d/2, t, ph/2])
                    rotate([-90, 0, 0])
                        cylinder(h=peg_l, d=peg_d, $fn=30);
                // Peg tip ball
                translate([i * sp + peg_d/2, t + peg_l, ph/2])
                    sphere(d=peg_d + 2, $fn=30);
            }
        }
        // Mounting holes
        for (x = [5, total_w - 15]) {
            translate([x, -1, ph/2])
                rotate([-90, 0, 0])
                    cylinder(h=t+2, d=hd, $fn=20);
        }
    }
}

coat_hook();

hinge_box.scad_template:
// Print-in-Place Hinge Box
w = ${width};
d = ${depth};
h = ${height};
wall = ${wall};
segs = ${hinge_segments};

hinge_w = 3;
seg_w = (w - wall) / segs;

module box_half() {
    difference() {
        cube([w, d, h]);
        translate([wall, wall, wall])
            cube([w - wall*2, d - wall*2, h]);
    }
}

// Bottom half
box_half();

// Living hinge
translate([0, d, 0])
    for (i = [0:segs-1]) {
        translate([wall/2 + i * seg_w, 0, 0])
            cube([seg_w * 0.6, hinge_w, wall * 0.5]);
    }

// Lid (flat, folds over)
translate([0, d + hinge_w, 0])
    cube([w, d, wall]);

funnel.scad_template:
// Parametric Funnel
md = ${mouth_dia};
sd = ${spout_dia};
h = ${height};
sl = ${spout_length};
wall = ${wall};

module funnel() {
    difference() {
        union() {
            // Cone
            cylinder(h=h-sl, d1=sd+wall*2, d2=md+wall*2, $fn=80);
            // Spout
            translate([0, 0, -(sl)])
                cylinder(h=sl, d=sd+wall*2, $fn=40);
            // Rim
            translate([0, 0, h-sl])
                difference() {
                    cylinder(h=3, d=md+wall*4, $fn=80);
                    translate([0, 0, -0.1])
                        cylinder(h=3.2, d=md, $fn=80);
                }
        }
        // Hollow inside
        translate([0, 0, -sl-0.1])
            cylinder(h=sl+0.2, d=sd, $fn=40);
        translate([0, 0, -0.1])
            cylinder(h=h-sl+0.2, d1=sd, d2=md, $fn=80);
    }
}

funnel();

measuring_scoop.scad_template:
// Parametric Measuring Scoop
vol = ${volume_ml};
hl = ${handle_length};
wall = ${wall};

// Approximate bowl radius from volume (hemisphere: V = 2/3 * pi * r^3)
bowl_r = pow(vol * 1000 * 3 / (2 * 3.14159), 1/3);

module scoop() {
    // Bowl
    difference() {
        sphere(r=bowl_r + wall, $fn=60);
        sphere(r=bowl_r, $fn=60);
        translate([0, 0, bowl_r/2])
            cube([bowl_r*4, bowl_r*4, bowl_r*2], center=true);
        translate([0, 0, -(bowl_r+wall+1)])
            cube([bowl_r*4, bowl_r*4, (bowl_r+wall)*2], center=true);
    }
    // Flat bottom
    translate([0, 0, -(bowl_r*0.3)])
        cylinder(h=wall, r=bowl_r*0.7, $fn=60);
    // Handle
    translate([bowl_r + wall, -wall, -wall])
        hull() {
            cube([1, wall*2, bowl_r*0.6]);
            translate([hl, wall*0.3, bowl_r*0.1])
                cube([1, wall*1.4, bowl_r*0.4]);
        }
}

scoop();

wall_plate_cover.scad_template:
// Parametric Wall Plate Cover
style = "${style}";
pw = ${plate_width};
ph = ${plate_height};
cr = ${corner_radius};
t = 3;

module rounded_rect(w, h, r) {
    if (r > 0) {
        hull() {
            for (x = [r, w-r]) for (y = [r, h-r])
                translate([x, y]) circle(r=r, $fn=20);
        }
    } else {
        square([w, h]);
    }
}

module plate() {
    difference() {
        // Plate body
        linear_extrude(height=t)
            rounded_rect(pw, ph, cr);
        // Center cutout based on style
        if (style == "single_toggle") {
            translate([pw/2, ph/2, -0.1])
                linear_extrude(height=t+0.2)
                    square([10, 28], center=true);
        }
        if (style == "double_toggle") {
            for (dy = [-20, 20]) {
                translate([pw/2, ph/2 + dy, -0.1])
                    linear_extrude(height=t+0.2)
                        square([10, 28], center=true);
            }
        }
        if (style == "outlet") {
            translate([pw/2, ph/2, -0.1])
                linear_extrude(height=t+0.2)
                    square([28, 34], center=true);
        }
        // Screw holes
        for (dy = [-30, 30]) {
            translate([pw/2, ph/2 + dy, -0.1])
                cylinder(h=t+0.2, d=4, $fn=20);
        }
    }
}

plate();

soap_dish.scad_template:
// Parametric Soap Dish
w = ${width};
d = ${depth};
h = ${height};
ridges = ${ridge_count};
cr = ${corner_radius};
wall = 3;

module rounded_box(w, d, h, r) {
    hull() {
        for (x = [r, w-r]) for (y = [r, d-r])
            translate([x, y, 0]) cylinder(h=h, r=r, $fn=20);
    }
}

module dish() {
    difference() {
        rounded_box(w, d, h, cr);
        translate([wall, wall, wall])
            rounded_box(w-wall*2, d-wall*2, h, max(1, cr-wall));
    }
    // Drain ridges
    ridge_sp = (w - wall*2 - 4) / (ridges - 1);
    for (i = [0:ridges-1]) {
        translate([wall + 2 + i * ridge_sp, wall + 2, wall])
            cube([2, d - wall*2 - 4, 3]);
    }
    // Drain holes in base
    // (slope the base slightly for drainage)
}

dish();

spool_holder.scad_template:
// Parametric Spool Holder
sw = ${spool_width};
sd = ${spool_dia};
rd = ${roller_dia};
wall = ${wall};

base_w = sw + wall * 4;
base_d = sd * 0.6;
base_h = wall;
roller_spacing = sd * 0.35;

module spool_holder() {
    // Base plate
    cube([base_w, base_d, base_h]);
    // Side walls
    for (x = [0, base_w - wall]) {
        translate([x, 0, 0])
            cube([wall, base_d, sd/4]);
    }
    // Roller cradles
    for (y = [base_d/2 - roller_spacing/2, base_d/2 + roller_spacing/2]) {
        translate([0, y, 0]) {
            // Roller support posts
            for (x = [wall, base_w - wall*2]) {
                translate([x, -wall, 0])
                    cube([wall, wall*2, rd + wall]);
            }
        }
    }
}

spool_holder();

tube_connector.scad_template:
// Parametric Tube Connector
tod = ${tube_od};
wall = ${wall};
len = ${length};
ang = ${angle};

od = tod + wall * 2;
bend_r = od * 2;

module connector() {
    if (ang == 0) {
        // Straight connector
        difference() {
            cylinder(h=len*2, d=od, $fn=50, center=true);
            cylinder(h=len*2+2, d=tod, $fn=50, center=true);
        }
    } else {
        // Angled connector
        difference() {
            union() {
                cylinder(h=len, d=od, $fn=50);
                translate([0, 0, len])
                    rotate([ang, 0, 0])
                        cylinder(h=len, d=od, $fn=50);
                // Elbow joint
                translate([0, 0, len])
                    sphere(d=od, $fn=50);
            }
            union() {
                cylinder(h=len+1, d=tod, $fn=50);
                translate([0, 0, len])
                    rotate([ang, 0, 0])
                        cylinder(h=len+1, d=tod, $fn=50);
                translate([0, 0, len])
                    sphere(d=tod, $fn=50);
            }
        }
    }
}

connector();

battery_holder.scad_template:
// Parametric Battery Holder
btype = "${battery_type}";
count = ${count};
wall = ${wall};

// Battery dimensions (diameter, length)
bd = (btype == "AAA") ? 10.5 : (btype == "18650") ? 18.6 : 14.5;
bl = (btype == "AAA") ? 44.5 : (btype == "18650") ? 65 : 50.5;

slot_w = bd + 1;
total_w = count * (slot_w + wall) + wall;

module holder() {
    difference() {
        cube([total_w, bl + wall * 2, bd/2 + wall + 2]);
        for (i = [0:count-1]) {
            // Battery slot
            translate([wall + i * (slot_w + wall) + slot_w/2, wall, bd/2 + wall])
                rotate([-90, 0, 0])
                    cylinder(h=bl, d=bd + 0.5, $fn=30);
            // Finger scoop for removal
            translate([wall + i * (slot_w + wall) + slot_w/2, wall + bl/2, bd + wall + 2])
                cylinder(h=5, d=bd * 0.6, $fn=20);
        }
    }
    // Snap ridges
    for (i = [0:count-1]) {
        for (y = [wall + 5, wall + bl - 5]) {
            translate([wall + i * (slot_w + wall) + 1, y, bd/2 + wall - 1])
                cube([slot_w - 2, 2, 1.5]);
        }
    }
}

holder();

wrench.scad_template:
// Parametric Wrench
bolt = ${bolt_size_mm};
hl = ${handle_length};
t = ${thickness};

jaw = bolt * 1.15;  // Slight clearance
head_r = jaw * 0.9;

module wrench() {
    linear_extrude(height=t) {
        difference() {
            union() {
                // Head
                circle(r=head_r, $fn=60);
                // Handle
                translate([0, -head_r * 0.4])
                    square([hl, head_r * 0.8]);
                // Handle end bulge
                translate([hl, 0])
                    circle(r=head_r * 0.5, $fn=40);
            }
            // Jaw opening (hex shape)
            rotate([0, 0, 30])
                circle(d=jaw / cos(30), $fn=6);
            // Jaw slot (open end)
            translate([-(jaw/2 + 1), 0])
                square([jaw/2 + 1, head_r + 1]);
        }
    }
}

wrench();

spacer_washer.scad_template:
// Parametric Spacer/Washer
id = ${inner_dia};
od = ${outer_dia};
t = ${thickness};

difference() {
    cylinder(h=t, d=od, $fn=60);
    translate([0, 0, -0.1])
        cylinder(h=t+0.2, d=id, $fn=60);
}

corner_brace.scad_template:
// Parametric Corner Brace
al = ${arm_length};
w = ${width};
t = ${thickness};
hd = ${hole_dia};
hn = ${holes_per_arm};

module brace() {
    difference() {
        union() {
            cube([al, w, t]);
            cube([t, w, al]);
            // Gusset triangle
            linear_extrude(height=w)
                polygon([[t, 0, 0], [al*0.6, 0], [t, al*0.6]]);
        }
        // Horizontal arm holes
        for (i = [1:hn]) {
            translate([t + (al-t) * i/(hn+1), w/2, -0.1])
                cylinder(h=t+0.2, d=hd, $fn=20);
        }
        // Vertical arm holes
        for (i = [1:hn]) {
            translate([-0.1, w/2, t + (al-t) * i/(hn+1)])
                rotate([0, 90, 0])
                    cylinder(h=t+0.2, d=hd, $fn=20);
        }
    }
}

brace();

standoff.scad_template:
