shaft_collar.scad_template:
// Parametric Shaft Collar
sd = ${shaft_dia};
cw = ${collar_width};
wall = ${wall};
bd = ${bolt_dia};

od = sd + wall * 2;

module collar() {
    difference() {
        cylinder(h=cw, d=od, $fn=60);
        // Shaft bore
        translate([0, 0, -0.1])
            cylinder(h=cw+0.2, d=sd+0.3, $fn=60);
        // Split gap
        translate([od/2-wall, -0.5, -0.1])
            cube([wall+1, 1, cw+0.2]);
        // Bolt hole through clamp ears
        translate([od/2-wall/2, 0, cw/2])
            rotate([90, 0, 0])
                cylinder(h=od+2, d=bd, $fn=20, center=true);
    }
}

collar();

pcb_standoff_mount.scad_template:
// Parametric PCB Mount
bw = ${board_width};
bd = ${board_depth};
sh = ${standoff_height};
