        // Servo cavity
        translate([wall, wall, wall])
            cube([sw + clear*2, sd + clear + 1, sh + 1]);
        // Mounting holes
        for (x = [wall, tw + clear*2 - wall - (tw - sw - wall*2)/2 + (tw - sw - wall*2)/2]) {
