module box() {
    difference() {
        cube([ow, od, ih + wall]);
        translate([wall, wall, wall])
            cube([iw, id, ih + 1]);
        // Lid tracks on inner sides
        for (x = [wall - td, ow - wall]) {
            translate([x, -0.1, ih + wall - tw - td])
                cube([td, od + 0.2, tw]);
        }
        // Lid entry slot at front
        translate([wall - td, -0.1, ih + wall - tw - td])
            cube([iw + td * 2, wall + 0.2, tw + td + 1]);
    }
}

module lid() {
    translate([ow + 10, 0, 0]) {
        cube([iw + td * 2 - 0.4, od + 5, tw - 0.3]);
        // Pull tab
        translate([(iw + td*2 - 0.4)/2 - 5, -8, 0])
            cube([10, 8, tw + 2]);
    }
}

