lip = 2;

module bin() {
    difference() {
        union() {
            // Outer shell
            cube([w, d, h]);
            // Stacking lip (extends above)
            translate([wall, wall, h])
                difference() {
                    cube([w - wall*2, d - wall*2, lip]);
                    translate([wall, wall, -0.1])
                        cube([w - wall*4, d - wall*4, lip+0.2]);
                }
        }
        // Inner cavity
        translate([wall, wall, wall])
            cube([w - wall*2, d - wall*2, h]);
        // Stacking recess at bottom
        translate([wall - 0.3, wall - 0.3, -0.1])
            difference() {
                cube([w - wall*2 + 0.6, d - wall*2 + 0.6, lip + 0.2]);
                translate([wall + 0.3, wall + 0.3, -0.1])
                    cube([w - wall*4, d - wall*4, lip + 0.4]);
            }
        // Label slot
        if (label == 1) {
            translate([w * 0.15, -0.1, h * 0.5])
                cube([w * 0.7, wall + 0.2, h * 0.35]);
        }
    }
}

