thread_depth = 1.2;

module thread_profile(od, turns) {
    for (a = [0:4:360*turns]) {
        translate([0, 0, a/360*pitch])
            rotate([0, 0, a])
                translate([od/2 - thread_depth, 0, 0])
                    cylinder(h=pitch*0.5, d1=thread_depth*2, d2=0, $fn=10);
    }
}

module jar() {
    difference() {
        cylinder(h=h, d=d, $fn=60);
        translate([0, 0, wall])
            cylinder(h=h, d=d - wall*2, $fn=60);
    }
    // External threads near top
    translate([0, 0, h - thread_h])
        thread_profile(d, thread_h/pitch);
}

module lid() {
    translate([d + 10, 0, 0]) {
        difference() {
            cylinder(h=thread_h + wall, d=d + wall*2 + thread_depth*2, $fn=60);
            translate([0, 0, wall])
                cylinder(h=thread_h + 1, d=d + 0.5, $fn=60);
        }
    }
}

