                    cylinder(h=cw, r=or, $fn=60);
            // Mounting flat on top
            translate([0, -or, or - wall])
                cube([cw, or * 2, wall]);
            // Bolt ears
            translate([0, or - wall, -or])
                cube([cw, wall * 2, or * 2]);
