    // Base plate
    cube([al, al, t]);
    // Diagonal brace
    translate([aw, aw, 0])
        linear_extrude(height=t)
            polygon([[0, 0], [al - aw, 0], [0, al - aw]]);
}

jig();

bench_dog.scad_template:
