module dog() {
    // Below-surface peg
    difference() {
        cylinder(h=pd, d=hd - 0.5, $fn=40);
        // Spring slot for friction fit
        translate([-spring_cut/2, -hd/2, 0])
            cube([spring_cut, hd, pd * 0.7]);
    }
    // Shoulder/stop
    translate([0, 0, pd])
        cylinder(h=3, d=head, $fn=40);
    // Above-surface head
    translate([0, 0, pd + 3])
        cylinder(h=ph - 3, d=head * 0.8, $fn=40);
}

dog();

hose_barb_adapter.scad_template:
// Parametric Hose Barb Adapter
sid = ${small_id};
lid = ${large_id};
bl = ${barb_length};
wall = ${wall};

barb_h = 1.2;
barbs = 3;
step = bl / barbs;

module barb_section(od, len) {
    for (i = [0:barbs-1]) {
        translate([0, 0, i * step])
            cylinder(h=step * 0.7, d1=od + barb_h, d2=od, $fn=30);
        translate([0, 0, i * step + step * 0.7])
            cylinder(h=step * 0.3, d=od, $fn=30);
    }
}

module adapter() {
    difference() {
        union() {
            // Small end barbs
            barb_section(sid + wall * 2, bl);
            // Center shoulder
            translate([0, 0, bl])
                cylinder(h=5, d=max(sid, lid) + wall * 2 + barb_h * 2, $fn=40);
            // Large end barbs
            translate([0, 0, bl + 5])
                barb_section(lid + wall * 2, bl);
        }
        // Through bore (stepped)
        translate([0, 0, -0.1])
            cylinder(h=bl + 5.2, d=sid, $fn=30);
        translate([0, 0, bl + 5])
            cylinder(h=bl + 0.1, d=lid, $fn=30);
    }
}

adapter();

drain_strainer.scad_template:
// Parametric Drain Strainer
dd = ${drain_dia};
rim = ${rim_width};
slots = ${slot_count};
t = ${thickness};

od = dd + rim * 2;
slot_w = 2;

module strainer() {
    difference() {
        union() {
            // Rim
            cylinder(h=t, d=od, $fn=60);
            // Recessed disc that sits inside drain
            translate([0, 0, -3])
                cylinder(h=3, d=dd - 1, $fn=60);
        }
        // Radial slots
        for (a = [0:360/slots:359]) {
            rotate([0, 0, a])
                translate([-slot_w/2, 5, -3.1])
                    cube([slot_w, dd/2 - 8, t + 3.2]);
        }
        // Center hole
        translate([0, 0, -3.1])
            cylinder(h=t + 3.2, d=8, $fn=20);
    }
}

strainer();

raspberry_pi_case.scad_template:
// Parametric RPi Case
bw = ${board_width};
bd = ${board_depth};
bh = ${board_height};
wall = ${wall};
vents = ${vent_slots};

clear = 1;
ow = bw + clear * 2 + wall * 2;
od = bd + clear * 2 + wall * 2;
oh = bh + wall * 2 + 3;

module case_bottom() {
    difference() {
        cube([ow, od, oh/2]);
        translate([wall, wall, wall])
            cube([bw + clear*2, bd + clear*2, oh]);
        // Port cutouts (USB side)
        translate([ow - wall - 0.1, wall + 10, wall + 3])
            cube([wall + 0.2, 40, 10]);
        // SD card slot
        translate([wall + bw/2 - 6, -0.1, wall])
            cube([12, wall + 0.2, 3]);
        // Ventilation
        if (vents == 1) {
            for (y = [wall + 5 : 4 : od - wall - 5]) {
                translate([-0.1, y, wall + 2])
                    cube([wall + 0.2, 2, oh/2 - wall - 4]);
            }
        }
    }
    // PCB standoffs
    for (x = [wall + clear + 3.5, wall + clear + bw - 3.5])
        for (y = [wall + clear + 3.5, wall + clear + bd - 3.5])
            translate([x, y, wall])
                difference() {
                    cylinder(h=3, d=6, $fn=20);
                    cylinder(h=3.1, d=2.7, $fn=20);
                }
}

module case_top() {
    translate([ow + 10, 0, 0]) {
        difference() {
            cube([ow, od, oh/2]);
            translate([wall, wall, -0.1])
                cube([bw + clear*2, bd + clear*2, oh/2 - wall + 0.1]);
        }
    }
}

case_bottom();
case_top();

