shower_caddy_hook.scad_template:
// Shower Caddy Hook
pd = ${pipe_dia};
hd = ${hook_depth};
w = ${width};
t = ${thickness};

module hook() {
    // Pipe clamp (270-degree arc)
    difference() {
        cylinder(h=w, d=pd+t*2, $fn=40);
        translate([0, 0, -0.1])
            cylinder(h=w+0.2, d=pd+0.5, $fn=40);
        // Opening slot
        translate([0, -pd/2-t, -0.1])
            cube([pd+t*2, pd/2+t, w+0.2]);
    }
    // Hook arm
    translate([pd/2+t/2, 0, 0])
        cube([t, hd, w]);
    // Hook curl
    translate([pd/2+t/2-8, hd-8, 0])
        difference() {
            cylinder(h=w, r=8+t, $fn=30);
            translate([0, 0, -0.1])
                cylinder(h=w+0.2, r=8, $fn=30);
            translate([-20, -20, -0.1])
                cube([40, 20, w+0.2]);
        }
}

hook();

cable_chain_link.scad_template:
