pd = ${pin_dia};

ow = iw + wall * 2;
oh = ih + wall * 2;

module link() {
    difference() {
        union() {
            // Main channel
            difference() {
                cube([ll, ow, oh]);
                translate([wall, wall, wall])
                    cube([ll - wall*2, iw, ih]);
            }
            // Pin cylinders at back
            for (y = [-1, ow+1])
                translate([ll-wall, y < 0 ? 0 : ow, oh/2])
                    rotate([90, 0, 0])
                        cylinder(h=wall, d=pd+wall, $fn=20);
        }
        // Pin holes at front
        translate([0, -1, oh/2])
            rotate([90, 0, 0])
                rotate([0, 90, 0])
                    cylinder(h=2, d=pd+0.3, $fn=20);
    }
}

