gear_spur.scad_template:
// Parametric Spur Gear
n = ${teeth};
m = ${module_mm};
fw = ${face_width};
bd = ${bore_dia};
pa = ${pressure_angle};

pitch_r = n * m / 2;
outer_r = pitch_r + m;
root_r = pitch_r - 1.25 * m;

module tooth() {
    tw = m * 3.14159 / 2;
    polygon([
        [root_r, -tw/2],
        [outer_r - 0.2, -tw/3],
        [outer_r, 0],
        [outer_r - 0.2, tw/3],
        [root_r, tw/2]
    ]);
}

module gear() {
    difference() {
        linear_extrude(height=fw) {
            difference() {
                circle(r=outer_r + 0.1, $fn=n*4);
                circle(r=root_r, $fn=n*4);
            }
            circle(r=root_r, $fn=n*4);
            for (i = [0:n-1])
                rotate([0, 0, i * 360/n])
                    tooth();
        }
        // Center bore
        translate([0, 0, -0.1])
            cylinder(h=fw+0.2, d=bd, $fn=30);
    }
}

gear();

pulley_gt2.scad_template:
// GT2 Timing Pulley
nt = ${teeth};
bd = ${bore_dia};
bw = ${belt_width};
fd = ${flange_dia};

pitch = 2; // GT2 = 2mm pitch
pr = nt * pitch / (2 * 3.14159);
or = pr + 0.25;
fh = 1.5; // flange height

module pulley() {
    difference() {
        union() {
            // Bottom flange
            cylinder(h=fh, d=fd, $fn=50);
            // Toothed section
            translate([0, 0, fh])
                cylinder(h=bw, r=or, $fn=nt*2);
            // Top flange
            translate([0, 0, fh + bw])
                cylinder(h=fh, d=fd, $fn=50);
        }
        // Bore
        translate([0, 0, -0.1])
            cylinder(h=bw + fh*2 + 0.2, d=bd, $fn=30);
        // Teeth grooves (simplified)
        for (i = [0:nt-1])
            rotate([0, 0, i * 360/nt])
                translate([pr, 0, fh - 0.1])
                    cylinder(h=bw+0.2, d=1, $fn=10);
    }
}

pulley();

