tool_holder_pegboard.scad_template:
// Pegboard Tool Holder
hl = ${hook_length};
hd = ${hook_dia};
ps = ${peg_spacing};
np = ${pegs};

module holder() {
    // Back pegs
    for (i = [0:np-1])
        translate([0, i * ps, 0]) {
            // Peg (into board)
            rotate([0, 90, 0])
                cylinder(h=15, d=hd-0.5, $fn=20);
            // Up hook
            translate([-15, 0, 0])
                cylinder(h=hd, d=hd, $fn=20);
        }
    // Connecting bar
    translate([-15, 0, 0])
        cube([hd, (np-1)*ps + hd, hd]);
    // Hook arm
    translate([-15, ((np-1)*ps)/2, 0])
        rotate([0, -90, 0])
            cylinder(h=hl, d=hd, $fn=20);
    // Hook tip (upward)
    translate([-15-hl, ((np-1)*ps)/2, 0])
        cylinder(h=15, d=hd, $fn=20);
}

holder();
